use crate::api::client::ApiClient;
use crate::constants;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities;
use std::collections::HashMap;

pub struct StatsCommand;

impl StatsCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = utilities::normalize_time_entry_list_filters(since, until)?;
        let entries = api_client.get_time_entries_filtered(since, until).await?;
        print!("{}", render_stats(&entries));
        Ok(())
    }
}

fn render_stats(entries: &[TimeEntry]) -> String {
    let mut project_durations: HashMap<String, i64> = HashMap::new();

    for entry in entries.iter().filter(|entry| entry.duration >= 0) {
        let project_name = entry
            .project
            .as_ref()
            .map(|project| project.name.clone())
            .unwrap_or_else(|| constants::NO_PROJECT.to_string());
        *project_durations.entry(project_name).or_default() += entry.duration;
    }

    let mut projects: Vec<_> = project_durations.into_iter().collect();
    projects.sort_by(|(name_a, duration_a), (name_b, duration_b)| {
        duration_b.cmp(duration_a).then_with(|| name_a.cmp(name_b))
    });

    let total: i64 = projects.iter().map(|(_, duration)| duration).sum();
    let mut output = projects
        .iter()
        .map(|(name, duration)| {
            format!(
                "{}  {name}",
                utilities::format_duration_compact(*duration)
            )
        })
        .collect::<Vec<_>>();
    output.push(format!(
        "{}  Total",
        utilities::format_duration_compact(total)
    ));
    output.join("\n") + "\n"
}

