    use super::{render_stats, render_stats_json};
    use crate::models::{Project, TimeEntry};
    use chrono::{TimeZone, Utc};

    fn project(id: i64, name: &str) -> Project {
        Project {
            id,
            name: name.to_string(),
            workspace_id: 1,
            client: None,
            is_private: false,
            active: true,
            at: Utc.timestamp_opt(0, 0).unwrap(),
            created_at: Utc.timestamp_opt(0, 0).unwrap(),
            color: String::new(),
            billable: None,
        }
    }

    fn entry(duration: i64, project: Option<Project>) -> TimeEntry {
        TimeEntry {
            duration,
            project,
            ..TimeEntry::default()
        }
    }

    #[test]
    fn renders_sorted_project_totals_and_skips_running_entries() {
        let entries = vec![
            entry(3720, Some(project(1, "Zed"))),
            entry(1800, Some(project(2, "Alpha"))),
            entry(900, Some(project(2, "Alpha"))),
            entry(2700, None),
            entry(-60, Some(project(3, "Running"))),
        ];

        assert_eq!(
            render_stats(&entries),
            "1h 02m  Zed\n45m  Alpha\n45m  No Project\n2h 32m  Total\n"
        );
    }

    #[test]
    fn renders_json_with_integer_seconds_and_matching_order() {
        let entries = vec![
            entry(3720, Some(project(1, "Zed"))),
            entry(1800, Some(project(2, "Alpha"))),
            entry(900, Some(project(2, "Alpha"))),
            entry(2700, None),
            entry(-60, Some(project(3, "Running"))),
        ];

        assert_eq!(
            render_stats_json(&entries),
            "{\"groups\":[{\"project\":\"Zed\",\"seconds\":3720},{\"project\":\"Alpha\",\"seconds\":2700},{\"project\":\"No Project\",\"seconds\":2700}],\"total_seconds\":9120}\n"
        );
    }
}
